function debounce(fn, delay) {
  let timer;

  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => {
      fn.apply(this, args);
    }, delay);
  };
}

// Usage
const handleSearch = debounce((query) => {
  console.log('Searching for:', query);
  fetchResults(query);
}, 400);

document.getElementById('search').addEventListener('input', (e) => {
  handleSearch(e.target.value);
});

function throttle(fn, limit) {
  let inThrottle = false;

  return function (...args) {
    if (inThrottle) return;

    fn.apply(this, args);
    inThrottle = true;

    setTimeout(() => {
      inThrottle = false;
    }, limit);
  };
}

// Usage: track scroll position without hammering the DOM
const handleScroll = throttle(() => {
  const scrollY = window.scrollY;
  updateProgressBar(scrollY);
}, 100);

window.addEventListener('scroll', handleScroll);

// Debounce: recalculate only after user stops resizing
window.addEventListener('resize', debounce(() => {
  recalculateLayout();
}, 300));

// Throttle: update every 200ms while resizing (live preview)
window.addEventListener('resize', throttle(() => {
  updateLivePreview();
}, 200));

function debounceLeading(fn, delay) {
  let timer;

  return function (...args) {
    const shouldFire = !timer;
    clearTimeout(timer);

    timer = setTimeout(() => {
      timer = null;
    }, delay);

    if (shouldFire) {
      fn.apply(this, args);
    }
  };
}

// Prevents accidental double-submits on a form button
const submitOrder = debounceLeading(() => {
  placeOrder();
}, 1000);
